"use client";

import { useState, useEffect, useRef } from "react";
import { Search, Loader2, School, GraduationCap, X } from "lucide-react";

interface InstitutionSearchProps {
  value: string;
  onChange: (value: string) => void;
}

export default function InstitutionSearch({ value, onChange }: InstitutionSearchProps) {
  const [type, setType] = useState<"university" | "school">("university");
  const [inputValue, setInputValue] = useState(value);
  const [results, setResults] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Sync internal state with prop if value changes from outside (e.g. form reset)
  useEffect(() => {
    setInputValue(value);
  }, [value]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (inputValue.length >= 5 && isOpen) {
        setIsLoading(true);
        try {
          const endpoint = type === "university" ? "/api/universities/search" : "/api/schools/search";
          const res = await fetch(`${endpoint}?name=${encodeURIComponent(inputValue)}`);
          const result = await res.json();
          if (result.is_success) {
            setResults(result.data);
          } else {
            setResults([]);
          }
        } catch (error) {
          console.error("Search error:", error);
          setResults([]);
        } finally {
          setIsLoading(false);
        }
      } else {
        setResults([]);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [inputValue, type, isOpen]);

  const handleSelect = (name: string) => {
    setInputValue(name);
    onChange(name);
    setIsOpen(false);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setInputValue(val);
    onChange(val);
    setIsOpen(true);
  };

  return (
    <div className="relative" ref={dropdownRef}>
      {/* Type Toggle */}
      <div className="flex gap-2 mb-2">
        <button
          type="button"
          onClick={() => {
            setType("university");
            setResults([]);
          }}
          className={`flex-1 flex items-center justify-center gap-2 py-2 px-3 rounded-xl text-xs font-medium transition-all ${
            type === "university"
              ? "bg-blue-600 text-white shadow-lg shadow-blue-900/20"
              : "bg-slate-800 text-slate-400 hover:bg-slate-700"
          }`}
        >
          <GraduationCap className="w-4 h-4" />
          Kampus
        </button>
        <button
          type="button"
          onClick={() => {
            setType("school");
            setResults([]);
          }}
          className={`flex-1 flex items-center justify-center gap-2 py-2 px-3 rounded-xl text-xs font-medium transition-all ${
            type === "school"
              ? "bg-blue-600 text-white shadow-lg shadow-blue-900/20"
              : "bg-slate-800 text-slate-400 hover:bg-slate-700"
          }`}
        >
          <School className="w-4 h-4" />
          Sekolah
        </button>
      </div>

      {/* Input Field */}
      <div className="relative">
        <input
          type="text"
          required
          value={inputValue}
          onChange={handleInputChange}
          onFocus={() => setIsOpen(true)}
          placeholder={type === "university" ? "Cari nama kampus..." : "Cari nama sekolah..."}
          className="w-full bg-slate-800 border border-slate-700 rounded-xl pl-11 pr-4 py-3 text-white placeholder:text-slate-500 focus:outline-none focus:border-blue-500 transition-colors"
        />
        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
          ) : (
            <Search className="w-5 h-5" />
          )}
        </div>
        {inputValue && (
          <button
            type="button"
            onClick={() => {
              setInputValue("");
              onChange("");
              setResults([]);
            }}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-slate-300 transition-colors"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </div>

      {/* Dropdown Results */}
      {isOpen && (
        <div className="absolute z-50 left-0 right-0 mt-2 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl max-h-64 overflow-y-auto scrollbar-thin scrollbar-thumb-slate-600 scrollbar-track-transparent">
          {inputValue.length < 5 ? (
            <div className="p-4 text-center">
              <p className="text-sm text-slate-400 italic">Ketik minimal 5 huruf untuk mencari...</p>
            </div>
          ) : isLoading ? (
            <div className="p-4 flex flex-col gap-2">
              {[1, 2, 3].map((i) => (
                <div key={i} className="h-8 bg-slate-700/50 animate-pulse rounded-lg" />
              ))}
            </div>
          ) : results.length > 0 ? (
            <div className="py-2">
              {results.map((name, index) => (
                <button
                  key={index}
                  type="button"
                  onClick={() => handleSelect(name)}
                  className="w-full text-left px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white transition-colors border-b border-slate-700/50 last:border-0"
                >
                  {name}
                </button>
              ))}
            </div>
          ) : (
            <div className="p-4 text-center">
              <p className="text-sm text-slate-400">Tidak menemukan {type === "university" ? "kampus" : "sekolah"} tersebut. Kamu bisa lanjut mengetik manual.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
